// Extraire l'heure du message "dors HH:MM"
const text = $input.item.json.message.text;
const match = text.match(/(\d{1,2})[h:](\d{2})/);

if (!match) {
  return { error: true, reply: "❌ Format invalide. Utilise : dors HH:MM" };
}

const heures = parseInt(match[1]);
const minutes = parseInt(match[2]);

if (heures > 23 || minutes > 59) {
  return { error: true, reply: "❌ Heure invalide. Utilise un format 00:00 à 23:59" };
}

const heureCoucher = `${String(heures).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;

return {
  error: false,
  heureCoucher,
  chatId: $input.item.json.message.chat.id,
  reply: `😴 Bonne nuit ! Coucher enregistré à ${heures}h${String(minutes).padStart(2, '0')}. Envoie \"réveil HH:MM\" demain matin.`
};

// Récupérer le message et les variables
const message = $('Telegram Trigger').item.json.message;
const text = message.text;
const chatId = message.chat.id;

// Parser l'heure de réveil
const matchReveil = text.match(/(\d{1,2})[h:](\d{2})/);
if (!matchReveil) {
  return {
    chatId,
    reply: "❌ Format invalide. Utilise : réveil HH:MM"
  };
}

const heuresReveil = parseInt(matchReveil[1]);
const minutesReveil = parseInt(matchReveil[2]);

if (heuresReveil > 23 || minutesReveil > 59) {
  return {
    chatId,
    reply: "❌ Heure invalide."
  };
}

// Chercher la variable de coucher dans les résultats de l'API
const variables = $('Récupérer Coucher (API)').first().json.data || $('Récupérer Coucher (API)').first().json;
const varName = `sleep_coucher_${chatId}`;

let coucherVar;
if (Array.isArray(variables)) {
  coucherVar = variables.find(v => v.key === varName);
} else {
  coucherVar = null;
}

if (!coucherVar || !coucherVar.value) {
  return {
    chatId,
    reply: "❌ Aucune heure de coucher enregistrée. Envoie d'abord : dors HH:MM"
  };
}

// Parser l'heure de coucher
const [hCoucher, mCoucher] = coucherVar.value.split(':').map(Number);

// Calcul de la durée en minutes
// Gère le passage de minuit (ex: coucher 23:30, réveil 07:15)
let minutesCoucher = hCoucher * 60 + mCoucher;
let minutesReveilTotal = heuresReveil * 60 + minutesReveil;

// Si le réveil est "avant" le coucher, on a passé minuit
let dureeMinutes;
if (minutesReveilTotal >= minutesCoucher) {
  dureeMinutes = minutesReveilTotal - minutesCoucher;
} else {
  // Passage de minuit : ex coucher 23:30 (1410) -> réveil 07:15 (435)
  dureeMinutes = (24 * 60 - minutesCoucher) + minutesReveilTotal;
}

const dureeH = Math.floor(dureeMinutes / 60);
const dureeM = dureeMinutes % 60;

// Déterminer la qualité du sommeil
let commentaire;
let emoji;
if (dureeMinutes >= 8 * 60) {
  commentaire = "Excellente nuit !";
  emoji = "🌟";
} else if (dureeMinutes >= 7 * 60) {
  commentaire = "Bonne nuit !";
  emoji = "✅";
} else if (dureeMinutes >= 6 * 60) {
  commentaire = "Correct, mais essaie de dormir plus.";
  emoji = "😐";
} else {
  commentaire = "Insuffisant ! Pense à te coucher plus tôt.";
  emoji = "⚠️";
}

// Formater la date de la nuit
const now = new Date();
const hier = new Date(now);
// Si le coucher est le soir (>= 18h), la nuit a commencé hier
if (hCoucher >= 18) {
  hier.setDate(hier.getDate() - 1);
}
const jourNuit = `${String(hier.getDate()).padStart(2, '0')}/${String(hier.getMonth() + 1).padStart(2, '0')}`;

const hCoucherStr = `${String(hCoucher).padStart(2, '0')}h${String(mCoucher).padStart(2, '0')}`;
const hReveilStr = `${String(heuresReveil).padStart(2, '0')}h${String(minutesReveil).padStart(2, '0')}`;
const dureeStr = `${dureeH}h${String(dureeM).padStart(2, '0')}`;

const reply = `🛏️ Nuit du ${jourNuit} → Tu as dormi ${dureeStr}.\nCoucher : ${hCoucherStr} | Réveil : ${hReveilStr}\n${emoji} ${commentaire}`;

return {
  chatId,
  reply
};
